import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useCart } from '../context/CartContext';

const Navbar = ({ onCategory, onSearch }) => {
  const { user, logout } = useAuth();
  const { totalItems } = useCart();
  const navigate = useNavigate();
  const [search, setSearch] = useState('');
  const [searchFocused, setSearchFocused] = useState(false);

  const handleLogout = () => { logout(); navigate('/login'); };

  const handleSearch = (e) => {
    setSearch(e.target.value);
    if (onSearch) onSearch(e.target.value);
  };

  const handleCategory = (cat) => {
    if (onCategory) onCategory(cat);
    navigate('/');
  };

  const categories = [
    { name: 'All', icon: '🏠' },
    { name: 'Electronics', icon: '📱' },
    { name: 'Clothing', icon: '👕' },
    { name: 'Books', icon: '📚' },
    { name: 'Shoes', icon: '👟' },
    { name: 'Beauty', icon: '💄' },
    { name: 'Sports', icon: '⚽' },
    { name: 'Home', icon: '🏡' },
  ];

  return (
    <nav style={styles.nav}>
      {/* Top announcement bar */}
      <div style={styles.announcementBar}>
        🎉 Free shipping on orders over ₹50 &nbsp;|&nbsp; 🔥 Up to 40% off on Electronics &nbsp;|&nbsp; 💎 Premium quality guaranteed
      </div>

      {/* Main navbar */}
      <div style={styles.topBar}>
        {/* Logo */}
        <Link to="/" style={styles.brand} onClick={() => handleCategory('All')}>
          <span style={styles.brandIcon}>🛒</span>
          <span style={styles.brandText}>Cartify</span>
        </Link>

        {/* Search */}
        <div style={{ ...styles.searchBar, boxShadow: searchFocused ? '0 0 0 3px rgba(233,69,96,0.2)' : 'none' }}>
          <input
            placeholder="Search for products, brands and more..."
            value={search}
            onChange={handleSearch}
            onFocus={() => setSearchFocused(true)}
            onBlur={() => setSearchFocused(false)}
            style={styles.searchInput}
          />
          <button style={styles.searchBtn}>🔍</button>
        </div>

        {/* Right side */}
        <div style={styles.rightLinks}>
          {user ? (
            <>
              <div style={styles.userInfo}>
                <span style={styles.greeting}>Hello, {user.name.split(' ')[0]}</span>
                <div style={styles.userLinks}>
                  <Link to="/orders" style={styles.link}>My Orders</Link>
                  {user.isAdmin && <Link to="/admin" style={styles.adminLink}>⚙️ Admin</Link>}
                  <button onClick={handleLogout} style={styles.logoutBtn}>Logout</button>
                </div>
              </div>
            </>
          ) : (
            <div style={styles.authLinks}>
              <Link to="/login" style={styles.signInBtn}>Sign In</Link>
              <Link to="/register" style={styles.registerBtn}>Register</Link>
            </div>
          )}
          <Link to="/cart" style={styles.cartBtn}>
            <span style={styles.cartIcon}>🛒</span>
            <div style={styles.cartInfo}>
              <span style={styles.cartLabel}>Cart</span>
              {totalItems > 0 && <span style={styles.badge}>{totalItems}</span>}
            </div>
          </Link>
        </div>
      </div>

      {/* Category bar */}
      <div style={styles.bottomBar}>
        {categories.map(c => (
          <button
            key={c.name}
            onClick={() => handleCategory(c.name)}
            style={styles.navLink}
            onMouseEnter={e => {
              e.currentTarget.style.color = '#e94560';
              e.currentTarget.style.borderBottom = '2px solid #e94560';
            }}
            onMouseLeave={e => {
              e.currentTarget.style.color = '#ccc';
              e.currentTarget.style.borderBottom = '2px solid transparent';
            }}
          >
            {c.icon} {c.name === 'Home' ? 'Home & Kitchen' : c.name}
          </button>
        ))}
        <button style={styles.dealBtn} onClick={() => handleCategory('Electronics')}>
          🔥 Today's Deals
        </button>
      </div>
    </nav>
  );
};

const styles = {
  nav: { background: '#1a1a2e', position: 'sticky', top: 0, zIndex: 100, boxShadow: '0 4px 20px rgba(0,0,0,0.3)' },
  announcementBar: { background: 'linear-gradient(90deg, #e94560, #c62a47)', color: '#fff', textAlign: 'center', padding: '8px', fontSize: '13px', fontWeight: '500', letterSpacing: '0.3px' },
  topBar: { display: 'flex', alignItems: 'center', gap: '16px', padding: '14px 32px', flexWrap: 'wrap' },
  brand: { display: 'flex', alignItems: 'center', gap: '8px', textDecoration: 'none', flexShrink: 0 },
  brandIcon: { fontSize: '28px' },
  brandText: { color: '#fff', fontSize: '26px', fontWeight: '800', letterSpacing: '-0.5px', background: 'linear-gradient(135deg, #fff, #e94560)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' },
  searchBar: { flex: 1, display: 'flex', minWidth: '200px', borderRadius: '12px', overflow: 'hidden', border: '2px solid transparent', transition: 'box-shadow 0.2s' },
  searchInput: { flex: 1, padding: '12px 18px', border: 'none', fontSize: '15px', outline: 'none', background: '#f8f8f8' },
  searchBtn: { padding: '12px 20px', background: '#e94560', color: '#fff', border: 'none', cursor: 'pointer', fontSize: '16px', transition: 'background 0.2s' },
  rightLinks: { display: 'flex', alignItems: 'center', gap: '16px', flexShrink: 0 },
  userInfo: { display: 'flex', flexDirection: 'column', gap: '2px' },
  greeting: { color: '#aaa', fontSize: '12px' },
  userLinks: { display: 'flex', gap: '12px', alignItems: 'center' },
  link: { color: '#fff', textDecoration: 'none', fontSize: '13px', fontWeight: '600' },
  adminLink: { color: '#ffd700', textDecoration: 'none', fontSize: '13px', fontWeight: '700' },
  logoutBtn: { background: 'transparent', color: '#aaa', border: '1px solid #444', padding: '4px 10px', borderRadius: '6px', cursor: 'pointer', fontSize: '12px' },
  authLinks: { display: 'flex', gap: '8px' },
  signInBtn: { color: '#fff', textDecoration: 'none', fontSize: '14px', padding: '8px 16px', border: '1px solid #555', borderRadius: '8px' },
  registerBtn: { color: '#fff', textDecoration: 'none', fontSize: '14px', padding: '8px 16px', background: '#e94560', borderRadius: '8px', fontWeight: '600' },
  cartBtn: { display: 'flex', alignItems: 'center', gap: '8px', color: '#fff', textDecoration: 'none', background: '#e94560', padding: '10px 18px', borderRadius: '10px', fontWeight: 'bold', flexShrink: 0 },
  cartIcon: { fontSize: '20px' },
  cartInfo: { display: 'flex', flexDirection: 'column', gap: '1px' },
  cartLabel: { fontSize: '14px', fontWeight: '700' },
  badge: { background: '#ffd700', color: '#1a1a2e', borderRadius: '10px', padding: '1px 7px', fontSize: '11px', fontWeight: 'bold', display: 'inline-block' },
  bottomBar: { background: '#16213e', padding: '0 32px', display: 'flex', gap: '4px', overflowX: 'auto', borderTop: '1px solid rgba(255,255,255,0.05)' },
  navLink: { color: '#ccc', background: 'none', border: 'none', borderBottom: '2px solid transparent', cursor: 'pointer', fontSize: '13px', whiteSpace: 'nowrap', padding: '12px 14px', transition: 'all 0.2s', fontWeight: '500' },
  dealBtn: { color: '#e94560', background: 'none', border: 'none', borderBottom: '2px solid transparent', cursor: 'pointer', fontSize: '13px', whiteSpace: 'nowrap', padding: '12px 14px', fontWeight: '700', marginLeft: 'auto' },
};

export default Navbar;
